<?phpif ($priv['etavern']==0) exit;$allparams = false;function selecteder($n, $vl, $s){	$r = '<select name='.$n.' class=items>';	foreach ($vl as $k=>$v) $r.='<option value="'.$k.'"'.(($k==$s) ? ' SELECTED' : '').'>'.$v.'</option>';	$r.='</select>';	return $r;}function aprm(){	GLOBAL $allparams;	if ($allparams!=false) return $allparams;	$ra = Array();	$raa = all_params();	foreach ($raa as $k=>$v)	{		$ra[$v] = name_of_skill($v);	}	$allparams = $ra;	return $ra;}function params_generic($pr, $tp=0){	$r = '<table width=100% border=0 align="center">';	$pr = explode('@', $pr);	$i=0;	$ra = aprm();	$pal = Array();	foreach ($pr as $rs)	{		if ($rs != true) continue;		$rs = explode('=', $rs);		$pal[$rs[0]] = $rs[1];	}		foreach ($ra as $k=>$v)	{		$i++;		$bg = ($i%2) ? '#DDDDDD' : '#EEEEEE';		$r.= '<tr bgcolor="'.$bg.'"><td class=timef>'.$v.'</td><td class=timef><input class=login type=text name="'.(!$tp ? 'pls_' : 'mns_').$k.'" value="'.($pal[$k] ? $pal[$k] : 0).'"></td></tr>';	}	$r.= '<tr bgcolor="'.$bg.'"><td class=red><b>Время действия</b> (в секундах)</td><td class=timef><input class=login type=text name="'.(!$tp ? 'pls_' : 'mns_').'time" value="'.$pal['time'].'"></td></tr>';	$r.= '</table>';	return $r;}function edit_params_all($tp=0){	$r = '';	$pst = Array();	$tp = (!$tp ? 'pls_' : 'mns_');	foreach ($_POST as $kay=>$value)	{		if ( !preg_match('/'.$tp.'/', $kay) ) continue;		$nm = str_replace($tp, '', $kay);		$pst[$nm] = $value;	}		foreach ($pst as $k=>$v)	{		if (!$v) continue;		$r.= $k.'='.$v.'@';	}	return $r;}echo '<a href="main.php?go=administration" class="bga">Главная панель администратора</a>';if ( isset($_GET['edit']) ){	echo '<a href="main.php" class="bg">Назад</a>';	$nm = Array('open'=>'Статус', 'name'=>'Название', 'params'=>'Параметры', /*'othodnak'=>'Похмелье',*/ 'count'=>'Количество', 'price'=>'Цена', 'level'=>'Требуемый уровень', 'type'=>'Тип ресурса');	if ( isset($_GET['save']) )	{		$sm = array_keys($nm);		$a = '';		foreach($_POST as $k=>$v)		{			if ( !in_array($k, $sm) ) continue;			else $a.='`'.$k.'`="'.$v.'", ';		}		$a.='`params`="'.edit_params_all(0).'"';		if (strlen($a)>0) $db->sql('UPDATE `taverna` SET '.$a.' WHERE `id`='.abs(intval($_GET['edit'])));		unset($rs);	}		$rs = $db->sqla('SELECT * FROM `taverna` WHERE `id`='.abs(intval($_GET['edit'])).' LIMIT 1');	$aV = Array(			'open'=> Array('Недоступен', 'Можно купить'),			'type'=> Array('Личное использование','Можно угащать','Еда')		);	$i=0;	echo "<br /><form action='main.php?edit=".$rs['id']."&save=1' method=post><input type=submit class=login style='width:100%' value='Сохранить'><table width=80% border=0 align='center'>";	foreach ($rs as $k=>$v)	{		if ( !is_string($k) or $k=='id') continue;		$i++;		$bg = ($i%2) ? '#DDDDDD' : '#EEEEEE';		if (!$nm[$k]) $nm[$k] = $k;		echo '<tr bgcolor="'.$bg.'"><td class=timef>'.$nm[$k].'</td><td>';		if ($k=='open' or $k=='type')		{			echo selecteder($k, $aV[$k], $v);		}		elseif ($k=='params') echo params_generic($v, 0);	//	elseif ($k=='othodnak') echo params_generic($v, 1);		else echo '<input class=login type=text name="'.$k.'" value="'.$v.'">';					echo '</td></tr>';			}	echo "</table><input type=submit class=login style='width:100%' value='Сохранить'></form><br />";	exit;}if ( isset($_GET['new']) ){	if ($_GET['new']=='alc')	{		$db->sql('INSERT INTO `taverna` (`name`) VALUES ("Новый напиток");');	} elseif ($_GET['new']=='eda')	{			}}if ( isset($_GET['adelete']) ){	$db->sql("DELETE FROM `taverna` WHERE `id`='".abs(intval($_GET['adelete']))."'");}echo '<table border="1" width="100%"><tr><td><a href="main.php?new=alc" class="bga">Новый напиток</a></td><!--<td><a href="main.php?new=eda" class="bga">Новая закуска</a></td>--></tr></table>';$res = $db->sql('SELECT * FROM `taverna` ORDER BY `price`');echo '<table border="1" width="100%" cellspacing="0" cellpadding="0" bordercolorlight=#C0C0C0 bordercolordark=#FFFFFF class=LinedTable>';while($z = mysql_fetch_assoc($res)){	echo "<tr>";	echo "<td width=10><img src='http://".IMG."/icons/del.png' onclick='if(confirm(\"Удалить???\")) location=\"main.php?adelete=".$z["id"]."\"' style='cursor:pointer'></td>";	echo "<td><a href=main.php?edit=".$z["id"]."><img src='http://".IMG."/icons/edit.png'></a></td><td class=user>«".$z["name"]."»</td>";		echo "<td class=".(($z['open']) ? 'green>Доступна' : 'red><b>Недоступна</b>')."</td>";	echo "<td class=lvl>Уровень: ".$z["level"]."</td>";	echo "<td class=timef>В таверне: ".$z['count']." шт.</td>";		switch ($z['type'])	{		case 0: $t1='red'; $t2='Личное использование'; break;		case 1: $t1='green'; $t2='Можно угащать'; break;		case 2: $t1='blue'; $t2='Еда'; break;	}	echo "<td class='".$t1."'>".$t2."</td>";	$c = round( ($z['level']+($z['price']*0.01))/($z['price']*0.02) );	echo "<td class='lvl'>Прирост в час: ".$c."</td>";	echo "<td class=time>".$z['price']." LN</td>";	echo "</tr>";}echo "</table>";?>